import React from "react";
import { Link, useLocation } from "react-router-dom";

function Navbar() {
  const location = useLocation();

  const isActive = (path) => {
    if (path === "/") return location.pathname === "/";
    return location.pathname.startsWith(path);
  };

  return (
    <nav className="navbar">
      <div className="container navbar-inner">
        <Link to="/" className="logo">
          Đặt<span>SânBóng</span>
        </Link>

        <div className="nav-search">
          <input type="text" placeholder="Tìm sân bóng, trận bóng..." readOnly />
        </div>

        <div className="nav-links">
          <Link className={isActive("/") ? "nav-link active" : "nav-link"} to="/">
            Trang chủ
          </Link>
          <Link
            className={isActive("/matches") ? "nav-link active" : "nav-link"}
            to="/matches"
          >
            Tìm trận
          </Link>
          <Link
            className={isActive("/fields") ? "nav-link active" : "nav-link"}
            to="/fields"
          >
            Sân bóng
          </Link>
          <Link
            className={isActive("/admin") ? "nav-link active" : "nav-link"}
            to="/admin/bookings"
          >
            Quản lý
          </Link>
        </div>

        <div className="nav-user">
          <button className="nav-user-btn">Tài khoản</button>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
